// The Central Catchment reservoirs (MacRitchie / Upper & Lower Peirce / Seletar)
// — slim, dendritic water bodies north of the island centre. Each is a set of
// branches (polylines of {x, y (cells), w (half-width cells)}) that fork like
// the real reservoirs, rather than round ponds. Shared by engine + renderer.
export function reservoirArea(size) {
  return { cx: size * 0.44, cy: size * 0.49, forestR: size * 0.22 };
}
export function reservoirBranches(size) {
  if (_resCache && _resSize === size) return _resCache;
  const k = size / 48;
  const P = (x, y, w) => ({ x: x * k, y: y * k, w: w * k });
  _resCache = [
    // MacRitchie (central) — a forking dendrite
    [P(24.0, 23.5, 0.40), P(24.2, 24.8, 0.55), P(24.0, 26.0, 0.50), P(23.5, 27.0, 0.40)],
    [P(24.0, 26.0, 0.45), P(25.5, 25.8, 0.40), P(26.6, 25.2, 0.30)],
    [P(24.2, 24.8, 0.40), P(22.8, 24.6, 0.34), P(21.8, 24.1, 0.26)],
    // Peirce (north-west) — small dendrite
    [P(22.0, 27.6, 0.34), P(21.0, 28.6, 0.46), P(20.4, 29.6, 0.40), P(20.0, 30.6, 0.28)],
    [P(21.0, 28.6, 0.34), P(19.8, 28.9, 0.30), P(18.9, 29.3, 0.24)],
    // Seletar (north-east) — small dendrite
    [P(25.6, 27.6, 0.34), P(26.6, 28.6, 0.46), P(27.0, 29.9, 0.40), P(27.3, 31.0, 0.28)],
    [P(26.6, 28.6, 0.30), P(27.8, 28.3, 0.30), P(28.6, 27.9, 0.24)],
  ];
  _resSize = size;
  return _resCache;
}
export function inReservoir(x, y, size) {
  const nx = (x + 0.5) / size, ny = (y + 0.5) / size;
  for (const poly of SG_RESERVOIRS) if (pointInPolygon(nx, ny, poly)) return true;
  return false;
}

// The Singapore River — traced faithfully from the 1966 survey map (the map owner's
// Coast-layer trace). A slim tidal channel: the mouth opens into the sea at the south
// coast (near the GPO/Fullerton/Anderson Bridge) and it winds inland through the
// downtown up toward Kim Seng. It is part of the sea, not a distinct river: rendered
// as pure sea-coloured water (no muddy bank) so it reads as a sea inlet, and its cells
// read as water via inRiver (unbuildable, blocks roads). Widths match the drawn banks
// (thin — ~0.9–1.7 world units half-width). Branch points are {x, y (cells), w
// (half-width cells)} in the 48-cell base grid, scaled to `size`. The first point sits
// at the shoreline so the channel joins the sea; the last tapers to the inland tip.
export function riverBranches(size) {
  if (_rivCache && _rivSize === size) return _rivCache;
  const k = size / 48;
  const P = (x, y, w) => ({ x: x * k, y: y * k, w: w * k });
  _rivCache = [
    // the course is sampled densely (~3.5-6u spacing) STRAIGHT OFF the owner's traced banks
    // with the TRACED widths — sparse control points let the swept curve sag off the drawn
    // line and a width floor made the water spill over the bank roads.
    [P(23.58, 18.78, 0.084), P(23.45, 18.79, 0.060), P(23.34, 18.78, 0.021), P(23.23, 18.75, 0.035),
     P(23.13, 18.86, 0.043), P(23.07, 18.99, 0.031), P(22.99, 19.07, 0.015), P(22.81, 19.09, 0.030),
     P(22.70, 19.05, 0.027), P(22.60, 19.18, 0.025), P(22.45, 19.16, 0.015), P(22.27, 19.16, 0.021),
     P(22.12, 19.04, 0.020), P(21.95, 19.08, 0.020), P(21.84, 19.11, 0.017), P(21.83, 19.26, 0.031),
     P(21.77, 19.34, 0.024), P(21.62, 19.34, 0.012),
     // continues inland as the canalised upper reach (the survey-map "Canal" toward Alexandra)
     P(21.30, 19.34, 0.021), P(21.00, 19.34, 0.020), P(20.66, 19.35, 0.019), P(20.34, 19.35, 0.014)],
  ];
  _rivSize = size;
  return _rivCache;
}
export function inRiver(x, y, size) {
  return nearBranches(x, y, riverBranches(size), 0.35);
}
// The Singapore River as a closed COASTLINE outline (normalised [nx,ny]) — its two banks
// offset from the swept centreline and joined into a loop. Used so the river reads as part
// of the traced coast: the map tracer (trace.html) shows it under the Coast layer.
export function riverOutline() {
  const br = riverBranches(48)[0], n = br.length, left = [], right = [];
  for (let i = 0; i < n; i++) {
    const a = br[Math.max(0, i - 1)], b = br[Math.min(n - 1, i + 1)], p = br[i];
    let tx = b.x - a.x, ty = b.y - a.y; const L = Math.hypot(tx, ty) || 1; tx /= L; ty /= L;
    const nx = -ty, ny = tx, w = p.w + 0.06;          // bank offset (a touch beyond the water edge)
    left.push([(p.x + nx * w) / 48, (p.y + ny * w) / 48]);
    right.push([(p.x - nx * w) / 48, (p.y - ny * w) / 48]);
  }
  return left.concat(right.reverse());
}

